import json
import re
import pandas as pd

data = locals()['var_function-call-15042493915336843920']
if isinstance(data, str) and data.endswith('.json'):
    with open(data, 'r') as f:
        businesses = json.load(f)
else:
    businesses = data

wifi_businesses = []
state_pattern = re.compile(r",\s+([A-Z]{2}),\s+this")

debug_log = []

for b in businesses:
    attrs = b.get('attributes')
    has_wifi = False
    if isinstance(attrs, dict):
        wifi_val = attrs.get('WiFi')
        # Check for 'free' or 'paid'. Clean string just in case.
        if wifi_val and isinstance(wifi_val, str):
            val_lower = wifi_val.lower()
            if 'free' in val_lower or 'paid' in val_lower:
                has_wifi = True

    if has_wifi:
        desc = b.get('description', '')
        match = state_pattern.search(desc)
        if match:
            state = match.group(1)
            wifi_businesses.append({
                'business_id': b['business_id'],
                'state': state
            })
        else:
            # Debug: why no match?
            if len(debug_log) < 5:
                debug_log.append(f"No state match for desc: {desc}")

result_payload = {}
if wifi_businesses:
    df = pd.DataFrame(wifi_businesses)
    state_counts = df['state'].value_counts()
    top_state = state_counts.idxmax()
    top_count = int(state_counts.max())
    target_ids = df[df['state'] == top_state]['business_id'].tolist()

    result_payload = {
        'status': 'success',
        'top_state': top_state,
        'count': top_count,
        'business_ids': target_ids,
        'debug_log': debug_log
    }
else:
    result_payload = {
        'status': 'empty',
        'debug_log': debug_log,
        'sample_attrs': [b.get('attributes') for b in businesses[:5]]
    }

print("__RESULT__:")
print(json.dumps(result_payload))

